const SHIPPING_FLAT=5,FREE_SHIP_THRESHOLD=45;function shippingCost(e){return e<=0||e>=45?0:5}function orderNumber(){return"MSC-"+Math.floor(1e5+9e5*Math.random())}function summaryMarkup(){const e=cartTotal(),n=shippingCost(e),i=e+n;return`\n    <h2>Order summary</h2>\n    ${cart.items.map(e=>{const n=PRODUCTS.find(n=>n.id===e.id);return`\n      <div class="summary__item">\n        <div class="summary__thumb">${productMedia(n,"thumb")}</div>\n        <div>\n          <div class="summary__name">${n.name}</div>\n          <div class="summary__qty">${n.origin} · Qty ${e.qty}</div>\n        </div>\n        <div class="summary__price">$${(n.price*e.qty).toFixed(2)}</div>\n      </div>`}).join("")}\n    <div class="summary__line"><span>Subtotal</span><span>$${e.toFixed(2)}</span></div>\n    <div class="summary__line"><span>Shipping</span><span>${0===n?"Free":"$"+n.toFixed(2)}</span></div>\n    <div class="summary__total"><span>Total</span><span>$${i.toFixed(2)}</span></div>\n    <p class="summary__note">${e>=45?"You've unlocked free shipping.":"Add $"+(45-e).toFixed(2)+" more for free shipping."}</p>`}function renderCheckout(){const e=document.getElementById("checkout");if(!e)return;if(0===cart.items.length)return void(e.innerHTML='\n      <div class="checkout__empty">\n        <h1>Your cart is empty</h1>\n        <p>Nothing to check out yet — go find something worth brewing.</p>\n        <a class="btn btn--solid" href="shop.html">Browse the roasts</a>\n      </div>');e.className="checkout",e.innerHTML=`\n    <form class="checkout__form" id="checkoutForm" novalidate>\n      <div class="checkout__head">\n        <h1>Checkout</h1>\n        <p>Roasted to order and shipped within 24 hours. This is a demo storefront — no card is charged.</p>\n      </div>\n\n      <div class="form-legend">Contact</div>\n      <div class="field">\n        <label for="co-name">Full name</label>\n        <input id="co-name" name="name" autocomplete="name" required />\n      </div>\n      <div class="field">\n        <label for="co-email">Email</label>\n        <input id="co-email" name="email" type="email" autocomplete="email" required />\n      </div>\n\n      <div class="form-legend">Shipping address</div>\n      <div class="field">\n        <label for="co-addr">Street address</label>\n        <input id="co-addr" name="address" autocomplete="street-address" required />\n      </div>\n      <div class="field-row">\n        <div class="field">\n          <label for="co-city">City</label>\n          <input id="co-city" name="city" autocomplete="address-level2" required />\n        </div>\n        <div class="field">\n          <label for="co-zip">Postal code</label>\n          <input id="co-zip" name="zip" autocomplete="postal-code" required />\n        </div>\n      </div>\n\n      <div class="form-legend">Payment</div>\n      <p class="pay-hint">Demo only — use any numbers, nothing is sent anywhere.</p>\n      <div class="field">\n        <label for="co-card">Card number</label>\n        <input id="co-card" name="card" inputmode="numeric" placeholder="4242 4242 4242 4242" required />\n      </div>\n      <div class="field-row">\n        <div class="field">\n          <label for="co-exp">Expiry</label>\n          <input id="co-exp" name="exp" placeholder="MM/YY" required />\n        </div>\n        <div class="field">\n          <label for="co-cvc">CVC</label>\n          <input id="co-cvc" name="cvc" inputmode="numeric" placeholder="123" required />\n        </div>\n      </div>\n\n      <button type="submit" class="btn btn--copper btn--block" id="placeOrder">\n        Place order · $${(cartTotal()+shippingCost(cartTotal())).toFixed(2)}\n      </button>\n    </form>\n\n    <aside class="summary" id="summary" aria-label="Order summary">\n      ${summaryMarkup()}\n    </aside>`;const n=document.getElementById("checkoutForm");n.addEventListener("submit",e=>{e.preventDefault();const i=n.querySelector("#co-email"),a=/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(i.value.trim());let r=null;if(n.querySelectorAll("input[required]").forEach(e=>{const n=!e.value.trim()||e===i&&!a;e.classList.toggle("invalid",n),n&&!r&&(r=e)}),r)return r.focus(),void showToast("Please fill in the highlighted fields.");completeOrder(i.value.trim())})}function completeOrder(e){const n=orderNumber();cart.items=[],saveCart(),updateCartUI();const i=document.getElementById("checkout");i.className="",i.innerHTML=`\n    <div class="checkout__confirm">\n      <div class="confirm-badge" aria-hidden="true">\n        <svg width="34" height="34" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.4" stroke-linecap="round" stroke-linejoin="round">\n          <path d="M20 6 9 17l-5-5"/>\n        </svg>\n      </div>\n      <h1>Order confirmed</h1>\n      <p>Thanks for your order. We're firing up the roaster now — your beans will ship within 24 hours.</p>\n      <p>A confirmation is on its way to <strong>${e}</strong>.</p>\n      <div class="order-ref">${n}</div>\n      <div>\n        <a class="btn btn--solid" href="shop.html">Keep shopping</a>\n      </div>\n    </div>`,window.scrollTo({top:0,behavior:"smooth"})}